INSERT INTO `medicine_info` (`name`, `specification`, `manufacturer`, `approval_number`, `usage_dosage`, `ingredients`, `indications`, `adverse_reactions`, `precautions`, `contraindications`, `expiry_date`) VALUES
                                                                                                                                                                                                                   ('阿莫西林胶囊', '0.25g*24粒', '修正药业集团股份有限公司', '国药准字H22023688', '口服。一次0.5g，每6-8小时1次，一日剂量不超过4g。', '阿莫西林', '用于敏感菌所致的各种感染，如中耳炎、鼻窦炎、咽炎、扁桃体炎等上呼吸道感染。', '恶心、呕吐、腹泻及假膜性肠炎等。', '青霉素类药物过敏者禁用。', '对青霉素类药物过敏者禁用。', '2026-12-31'),
                                                                                                                                                                                                                   ('布洛芬缓释胶囊', '0.3g*20粒', '中美天津史克制药有限公司', '国药准字H10900089', '口服。成人一次1粒，一日2次。', '布洛芬', '用于缓解轻至中度疼痛如头痛、关节痛、偏头痛、牙痛、肌肉痛、神经痛、痛经。也用于普通感冒或流行性感冒引起的发热。', '少数病人可出现恶心、呕吐、胃烧灼感或轻度消化不良、胃肠道溃疡及出血、头晕、耳鸣等。', '孕妇及哺乳期妇女禁用。', '对本品及其他非甾体抗炎药过敏者禁用。', '2026-06-30'),
                                                                                                                                                                                                                   ('维生素C片', '0.1g*100片', '华源众生药业有限公司', '国药准字H32020361', '口服。成人一次1片，一日3次。', '维生素C', '用于预防坏血病，也可用于各种急慢性传染疾病及紫癜等的辅助治疗。', '长期服用每日2-3g可引起停药后坏血病。', '不宜长期过量服用本品，否则，可能引起停药后坏血病。', '对本品过敏者禁用。', '2027-03-15'),
                                                                                                                                                                                                                   ('感冒灵颗粒', '10g*9袋', '华润三九医药股份有限公司', '国药准字Z44021940', '开水冲服，一次10克，一日3次。', '三叉苦、金盏银盘、野菊花、岗梅、薄荷油等', '解热镇痛。用于感冒引起的头痛，发热，鼻塞，流涕，咽痛。', '可见困倦、嗜睡、口渴、虚弱感。', '服药期间不得驾驶机、车、船、从事高空作业、机械作业及操作精密仪器。', '严重肝肾功能不全者禁用。', '2026-09-30'),
                                                                                                                                                                                                                   ('复方甘草片', '100片', '北京同仁堂股份有限公司', '国药准字Z11020355', '口服或含化。成人一次3-4片，一日3次。', '甘草流浸膏粉、阿片粉、樟脑、八角茴香油、苯甲酸钠', '镇咳祛痰。用于咳嗽气喘，多痰。', '有轻微的恶心、呕吐反应。', '本品不宜长期服用，如服用3-7天症状未缓解，请停药并咨询医师。', '孕妇及哺乳期妇女禁用。', '2027-01-31');
