INSERT INTO `conversation` (`user_id`, `session_id`, `role`, `content`) VALUES
                                                                            (1, 'session_001', 'user', '你好，我今天感觉有点头晕，血压正常吗？'),
                                                                            (1, 'session_001', 'assistant', '您好！根据您今天的健康数据，您的血压为120/80mmHg，处于正常范围。头晕可能与其他因素有关，建议您多休息，保持充足睡眠。如果症状持续，请及时就医。'),
                                                                            (1, 'session_001', 'user', '谢谢！我最近在服用阿莫西林，需要注意什么？'),
                                                                            (1, 'session_001', 'assistant', '服用阿莫西林时，请注意以下几点：1. 饭后服用，减少胃肠道刺激；2. 按时服药，不要随意停药；3. 如有过敏反应（如皮疹、呼吸困难），请立即停药并就医；4. 避免饮酒。祝您早日康复！'),
                                                                            (2, 'session_002', 'user', '我的血糖是4.8mmol/L，这个数值正常吗？'),
                                                                            (2, 'session_002', 'assistant', '您好！您的空腹血糖4.8mmol/L处于正常范围（正常空腹血糖为3.9-6.1mmol/L）。继续保持健康的生活方式，定期监测血糖。如果血糖持续偏高，建议控制饮食，适量运动。'),
                                                                            (3, 'session_003', 'user', '我血压135/88mmHg，需要担心吗？'),
                                                                            (3, 'session_003', 'assistant', '您好！您的血压135/88mmHg处于偏高范围（正常血压为<120/80mmHg，高血压前期为120-139/80-89mmHg）。建议您：1. 低盐低脂饮食；2. 适量运动，每周至少150分钟；3. 控制体重；4. 戒烟限酒；5. 定期监测血压。如果血压持续升高，建议咨询医生。');
